def detect_pitch(audio_chunk: bytes) -> float:
    response = requests.post(
        'https://api.pitchdetect.example.com/analyse',
        data=audio_chunk,
        headers={'Content-Type': 'audio/raw'}
    )
    return response.json()['fundamental_frequency']

def generate_feedback(detected_note, expected_note, raga):
    if detected_note == expected_note:
        return "Correct note."
    else:
        return f"Expected {expected_note}, played {detected_note}. Try again."

def save_practice_session(user_id: str, audio: bytes, session_metadata: dict):
    storage.save(
        path=f'practice/{user_id}/{session_metadata["timestamp"]}.wav',
        data=audio
    )
    db.insert('sessions', {**session_metadata, 'user_id': user_id})
